-- ============================================
-- Legislacao full-site: eduardo-braga / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2011-2026
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/4994/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2011_2026_20260506
--
-- Filtro factual: endpoint senador/4994/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=4994
--   com NumOrdemAutor=1. Resultado deste snapshot: 96 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-braga';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-braga: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('99927', '100082', '100634', '100732', '100738', '102690', '106364', '115478', '115630', '115631', '116009', '117582', '117572', '118547', '118548', '118549', '118550', '118551', '118552', '118554', '118555', '118556', '118558', '118559', '130955', '130960', '130964', '131368', '129267', '130959', '130963', '133518', '132355', '134207', '134203', '134206', '134212', '134361', '136153', '135595', '136117', '136976', '136079', '139697', '136960', '140310', '144067', '141200', '141436', '142400', '142455', '145490', '145617', '145618', '141208', '145849', '146715', '151259', '149695', '150391', '148915', '149363', '150408', '150410', '150411', '150412', '150427', '151103', '151104', '151105', '153500', '153857', '154142', '154143', '154144', '154255', '154256', '156786', '156787', '156789', '156790', '156791', '156792', '156793', '156794', '166711', '166712', '167641', '168368', '171717', '171718', '172783', '172867', '173516', '173634', '173825');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('99927', '100082', '100634', '100732', '100738', '102690', '106364', '115478', '115630', '115631', '116009', '117582', '117572', '118547', '118548', '118549', '118550', '118551', '118552', '118554', '118555', '118556', '118558', '118559', '130955', '130960', '130964', '131368', '129267', '130959', '130963', '133518', '132355', '134207', '134203', '134206', '134212', '134361', '136153', '135595', '136117', '136976', '136079', '139697', '136960', '140310', '144067', '141200', '141436', '142400', '142455', '145490', '145617', '145618', '141208', '145849', '146715', '151259', '149695', '150391', '148915', '149363', '150408', '150410', '150411', '150412', '150427', '151103', '151104', '151105', '153500', '153857', '154142', '154143', '154144', '154255', '154256', '156786', '156787', '156789', '156790', '156791', '156792', '156793', '156794', '166711', '166712', '167641', '168368', '171717', '171718', '172783', '172867', '173516', '173634', '173825')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-braga: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'AM'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2011;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-braga: mandato Senado/AM 2011-2026 nao encontrado em historico_politico';
  END IF;
END $$;

