    ('PL', '1952', 2019, 'Altera as Leis nos 11.482, de 31 de maio de 2007, e 9.249, de 26 de dezembro de 1995, e revoga dispositivos da Lei Complementar nº 123, de 14 de dezembro de 2006, da Lei nº 9.249, de 1995, e da Lei nº 11.033, de 21 de dezembro de 2004, para alterar a tabela progressiva do Imposto sobre a Renda da Pessoa Física; estabelecer a incidência do Imposto sobre a Renda sobre lucros e dividendos pagos ou creditados pelas pessoas jurídicas, incluídas as microempresas e empresas de pequeno porte optantes pelo Simples Nacional; extinguir a dedutibilidade dos juros sobre o capital próprio; reduzir a alíquota do Imposto sobre a Renda da Pessoa Jurídica; e afastar a isenção do Imposto sobre a Renda incidente sobre ativos financeiros.', 'Senado', '136117', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/136117', 'eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2011_2026_20260506', '{"proposicao_id_api":"136117","descricao_identificacao":"PL 1952/2019","data_apresentacao":"2019-04-02","casa":"SF","codigo_parlamentar_senado":4994,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"MDB","uf_autor_no_protocolo":"AM","autor_nome":"Eduardo Braga","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/4994/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/136117.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/136117.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/136117","coverage_id":"eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2011_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed"