    ('PL', '1757', 2023, 'Altera a Lei nº 6.259, de 30 de outubro de 1975, que dispõe sobre a organização das ações de Vigilância Epidemiológica, sobre o Programa Nacional de Imunizações, estabelece normas relativas à notificação compulsória de doenças, e dá outras providências, para tornar compulsória a notificação de uso de bebida alcoólica ou de outra substância psicoativa por criança ou adolescente.', 'Senado', '156794', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/156794', 'eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2011_2026_20260506', '{"proposicao_id_api":"156794","descricao_identificacao":"PL 1757/2023","data_apresentacao":"2023-04-11","casa":"SF","codigo_parlamentar_senado":4994,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"MDB","uf_autor_no_protocolo":"AM","autor_nome":"Eduardo Braga","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/4994/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/156794.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/156794.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/156794","coverage_id":"eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2011_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"eduardo-braga-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T04:42:54.968Z"}'::jsonb),
