DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-braga';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-braga: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_eduardo_braga_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'AM'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-braga: existem % anos de proposicoes Senado sem cobertura em mandato Senado/AM', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'eduardo-braga'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_eduardo_braga_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-braga';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-braga: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('99927', '100082', '100634', '100732', '100738', '102690', '106364', '115478', '115630', '115631', '116009', '117582', '117572', '118547', '118548', '118549', '118550', '118551', '118552', '118554', '118555', '118556', '118558', '118559', '130955', '130960', '130964', '131368', '129267', '130959', '130963', '133518', '132355', '134207', '134203', '134206', '134212', '134361', '136153', '135595', '136117', '136976', '136079', '139697', '136960', '140310', '144067', '141200', '141436', '142400', '142455', '145490', '145617', '145618', '141208', '145849', '146715', '151259', '149695', '150391', '148915', '149363', '150408', '150410', '150411', '150412', '150427', '151103', '151104', '151105', '153500', '153857', '154142', '154143', '154144', '154255', '154256', '156786', '156787', '156789', '156790', '156791', '156792', '156793', '156794', '166711', '166712', '167641', '168368', '171717', '171718', '172783', '172867', '173516', '173634', '173825');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'eduardo-braga-senado-completo-autoria-substantiva-2011-2026-20260506'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2011_2026_20260506';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 96 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-braga: esperadas 96 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 96 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-braga: esperadas 96 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-braga: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply eduardo-braga Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
